#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00333Custom {
public:
    __aicore__ inline KernelCa6k00333Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalSpatial, uint32_t tileSpatial,
                                uint32_t blockDim, uint32_t C,
                                uint32_t H, uint32_t W,
                                int32_t size, float alpha, float beta, float k) {
        totalSpatial_ = totalSpatial;
        tileSpatial_ = tileSpatial;
        C_ = C;
        H_ = H;
        W_ = W;
        alpha_ = alpha;
        beta_ = beta;
        k_ = k;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalSpatial_ * C_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalSpatial_ * C_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileSpatial_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileSpatial_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue_, 1, (tileSpatial_ * (C_ + 1)) * sizeof(float));
    }

    __aicore__ inline void Process() {
        if (totalSpatial_ == 0 || tileSpatial_ == 0) return;

        uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());
        uint32_t strideSpatial = blockNum * tileSpatial_;
        uint32_t baseSpatial = blockIdx * tileSpatial_;
        if (baseSpatial >= totalSpatial_) return;

        while (true) {
            uint32_t curSpatial = totalSpatial_ - baseSpatial;
            if (curSpatial > tileSpatial_) curSpatial = tileSpatial_;

            ComputeTile(baseSpatial, curSpatial);

            baseSpatial += strideSpatial;
            if (baseSpatial >= totalSpatial_) break;
        }
    }

private:
    __aicore__ inline void ComputeTile(uint32_t baseSpatial, uint32_t numSpatial) {
        // Allocate local buffers: sqSum (numSpatial), xCh (numSpatial * C)
        AscendC::LocalTensor<float> sqSum = tmpQueue_.AllocTensor<float>();
        AscendC::LocalTensor<float> xAll = sqSum + numSpatial;  // use remainder of tmpQueue

        // Initialize sqSum to 0
        AscendC::Dup(sqSum, 0.0f, numSpatial);

        // Load each channel and accumulate squares
        for (uint32_t c = 0; c < C_; c++) {
            AscendC::LocalTensor<float> xChan = xAll + c * numSpatial;
            // Copy one channel's tile
            AscendC::DataCopy(xChan, xGm_[baseSpatial + c * totalSpatial_], numSpatial);
            // Compute square and add to sqSum
            AscendC::Mul(xChan, xChan, xChan, numSpatial); // xChan now holds x^2
            AscendC::Add(sqSum, sqSum, xChan, numSpatial);
        }

        // Compute denominator: k + alpha * sqSum
        AscendC::Muls(sqSum, sqSum, alpha_, numSpatial);
        AscendC::Adds(sqSum, sqSum, k_, numSpatial);

        // Compute denom^(-beta) = exp(-beta * ln(denom))
        AscendC::Ln(sqSum, sqSum, numSpatial);
        AscendC::Muls(sqSum, sqSum, -beta_, numSpatial);
        AscendC::Exp(sqSum, sqSum, numSpatial);

        // Now multiply with original x to get output
        for (uint32_t c = 0; c < C_; c++) {
            AscendC::LocalTensor<float> xChan = xAll + c * numSpatial;
            // Reload original x for this channel (it was overwritten by square)
            AscendC::DataCopy(xChan, xGm_[baseSpatial + c * totalSpatial_], numSpatial);
            // Multiply with scale factor
            AscendC::Mul(xChan, xChan, sqSum, numSpatial); // result in xChan
            // Copy out to global
            AscendC::DataCopy(yGm_[baseSpatial + c * totalSpatial_], xChan, numSpatial);
        }

        tmpQueue_.FreeTensor(sqSum);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalSpatial_ {0};
    uint32_t tileSpatial_ {0};
    uint32_t C_ {0};
    uint32_t H_ {0};
    uint32_t W_ {0};
    float alpha_ {1e-4f};
    float beta_ {0.75f};
    float k_ {1.0f};
};

extern "C" __global__ __aicore__ void ca6k_00333_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling) {
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00333Custom op;
    op.Init(x, y,
            tiling_data.totalSpatial, tiling_data.tileSpatial,
            tiling_data.blockDim, tiling_data.C,
            tiling_data.H, tiling_data.W,
            tiling_data.size, tiling_data.alpha, tiling_data.beta, tiling_data.k);
    op.Process();
}
